const html = "\n        <div class=\"terms-page\">\n            <header class=\"terms-nav\">\n                <div class=\"terms-container terms-nav-inner\">\n                    <a class=\"brand terms-brand\" href=\"#\" data-navigate=\"welcome\" aria-label=\"ProcureX home\">\n                        \n        <span class=\"platform-logo\">\n            <img class=\"platform-logo-image\" src=\"/assets/logo.svg\" alt=\"ProcureX\">\n        </span>\n    \n                        <span class=\"brand-text\">ProcureX</span>\n                    </a>\n                    <nav class=\"terms-nav-links\" aria-label=\"Terms page navigation\">\n                        <a href=\"#\" data-navigate=\"guest-marketplace\">Open Tenders</a>\n                        <a href=\"#\" data-navigate=\"about-procurex\">About</a>\n                        <a href=\"#\" data-navigate=\"privacy-policy\">Privacy</a>\n                        <a class=\"active\" href=\"#\" data-navigate=\"terms-and-conditions\">Terms</a>\n                        <a href=\"#\" data-navigate=\"contact\">Contact</a>\n                    </nav>\n                    <div class=\"terms-nav-actions\">\n                        <a href=\"#\" data-navigate=\"sign-in\">Sign In</a>\n                        <button class=\"btn btn-primary\" type=\"button\" data-navigate=\"register\">Get Started</button>\n                    </div>\n                </div>\n            </header>\n\n            <main>\n                <section class=\"terms-hero\">\n                    <div class=\"terms-container terms-hero-grid\">\n                        <div class=\"terms-hero-copy animate-fade-in\">\n                            <span class=\"terms-eyebrow\">Terms and Conditions</span>\n                            <h1>Terms and Conditions for Using ProcureX</h1>\n                            <p class=\"terms-lead\">These Terms and Conditions explain the rules, responsibilities, rights, and limitations that apply when users access or use the ProcureX procurement platform.</p>\n                            <p>ProcureX is a digital procurement platform that allows buyers and suppliers to create accounts, publish tenders, submit bids, evaluate proposals, award tenders, negotiate contracts, manage procurement records, and complete post-award activities.</p>\n                            <p>By accessing or using ProcureX, you agree to follow these Terms and Conditions. If you do not agree with these Terms, you should not use the platform.</p>\n                            <div class=\"terms-actions\">\n                                <button class=\"btn btn-primary\" type=\"button\" data-navigate=\"register\">Accept and Continue</button>\n                                <button class=\"btn btn-secondary\" type=\"button\" data-navigate=\"contact\">Contact Support</button>\n                            </div>\n                        </div>\n\n                        <div class=\"terms-legal-visual animate-fade-in delay-1\" aria-label=\"Terms acceptance illustration\">\n                            <article class=\"terms-document\">\n                                <span>Digital contract</span>\n                                <h2>ProcureX Terms</h2>\n                                <p>Platform use agreement</p>\n                                <div><i></i><i></i><i></i></div>\n                            </article>\n                            <article class=\"terms-approval-card\">\n                                \n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M20 6 9 17l-5-5\"/>\n        </svg>\n    \n                                <strong>Approval badge</strong>\n                                <span>Read and accept before account creation</span>\n                            </article>\n                            <article class=\"terms-visual-row\">\n                                <strong>Buyer</strong>\n                                <span>creates tender</span>\n                            </article>\n                            <article class=\"terms-visual-row\">\n                                <strong>Supplier</strong>\n                                <span>submits bid</span>\n                            </article>\n                            <article class=\"terms-folder-card\">\n                                \n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M3 7h7l2 2h9v10H3z\"/><path d=\"M8 13h8\"/>\n        </svg>\n    \n                                <span>Secure document folder</span>\n                            </article>\n                            <label class=\"terms-accept-preview\">\n                                <input type=\"checkbox\" checked aria-label=\"Accepted preview\">\n                                <span>Terms acceptance required</span>\n                            </label>\n                        </div>\n                    </div>\n                </section>\n\n                <section class=\"terms-notice-band\">\n                    <div class=\"terms-container\">\n                        <article class=\"terms-notice\">\n                            <strong>Important Notice</strong>\n                            <p>ProcureX is a digital procurement platform. Unless expressly stated, ProcureX is not a buyer, supplier, contractor, consultant, agent, guarantor, or party to contracts formed between buyers and suppliers. Users are responsible for their own procurement decisions, documents, contracts, payments, and compliance obligations.</p>\n                        </article>\n                    </div>\n                </section>\n\n                <section class=\"terms-summary-band\">\n                    <div class=\"terms-container\">\n                        <div class=\"terms-section-heading\">\n                            <span class=\"terms-section-label\">Terms Summary</span>\n                            <h2>A clear platform-use agreement for procurement activity.</h2>\n                            <p>These Terms cover account responsibilities, buyer and supplier obligations, tender creation, bid submission, evaluation, awarding, contracting, payments, prohibited conduct, confidentiality, privacy, disputes, and platform limitations.</p>\n                        </div>\n                        <div class=\"terms-summary-grid\">\n                            \n                                <article>\n                                    <span>\n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M9 11l2 2 4-4\"/><path d=\"M5 5h14v14H5z\"/>\n        </svg>\n    </span>\n                                    <h3>Accurate information</h3>\n                                    <p>Users must provide truthful account, tender, bid, and contract information.</p>\n                                </article>\n                            \n                                <article>\n                                    <span>\n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M12 3l8 4v6c0 5-3.4 7.5-8 8-4.6-.5-8-3-8-8V7z\"/><path d=\"M9 9l6 6\"/><path d=\"M15 9l-6 6\"/>\n        </svg>\n    </span>\n                                    <h3>No fraud or corruption</h3>\n                                    <p>Bribery, collusion, bid rigging, fake documents, and misleading conduct are prohibited.</p>\n                                </article>\n                            \n                                <article>\n                                    <span>\n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M8 11V7a4 4 0 0 1 8 0v4\"/><rect x=\"5\" y=\"11\" width=\"14\" height=\"10\" rx=\"2\"/>\n        </svg>\n    </span>\n                                    <h3>Protect confidential data</h3>\n                                    <p>Tender, bid, financial, technical, and contract information must be handled responsibly.</p>\n                                </article>\n                            \n                                <article>\n                                    <span>\n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <circle cx=\"12\" cy=\"12\" r=\"9\"/><path d=\"M12 7v5l3 2\"/>\n        </svg>\n    </span>\n                                    <h3>Submit before deadline</h3>\n                                    <p>Users remain responsible for timing, uploads, file accuracy, and final review before submission.</p>\n                                </article>\n                            \n                                <article>\n                                    <span>\n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M6 3h12v18H6z\"/><path d=\"M9 8h6\"/><path d=\"M9 12h6\"/><path d=\"M9 16h4\"/>\n        </svg>\n    </span>\n                                    <h3>Respect platform rules</h3>\n                                    <p>Use ProcureX lawfully, professionally, and according to applicable procurement requirements.</p>\n                                </article>\n                            \n                        </div>\n                    </div>\n                </section>\n\n                <div class=\"terms-container terms-layout\">\n                    <aside class=\"terms-toc\" aria-label=\"Terms sections\">\n                        <strong>Terms sections</strong>\n                        <nav>\n                            <a href=\"#terms-introduction\">Introduction</a><a href=\"#terms-definitions\">Definitions</a><a href=\"#terms-acceptance\">Acceptance of Terms</a><a href=\"#terms-accounts\">User Accounts</a><a href=\"#terms-buyer-responsibilities\">Buyer Responsibilities</a><a href=\"#terms-supplier-responsibilities\">Supplier Responsibilities</a><a href=\"#terms-tender-creation\">Tender Creation</a><a href=\"#terms-bid-submission\">Bid Submission</a><a href=\"#terms-evaluation\">Evaluation</a><a href=\"#terms-awarding\">Awarding</a><a href=\"#terms-contracting\">Contracting</a><a href=\"#terms-payments\">Payments</a><a href=\"#terms-prohibited\">Prohibited Activities</a><a href=\"#terms-confidentiality\">Confidentiality</a><a href=\"#terms-privacy\">Privacy</a><a href=\"#terms-disputes\">Disputes</a><a href=\"#terms-liability\">Liability</a><a href=\"#terms-contact-form\">Contact</a>\n                        </nav>\n                    </aside>\n\n                    <div class=\"terms-content\">\n                        <section class=\"terms-section\">\n                            <span class=\"terms-section-label\">Buyer and Supplier Responsibilities</span>\n                            <h2>Responsibilities at a Glance</h2>\n                            <div class=\"terms-comparison\">\n                                <article>\n                                    <h3>Buyer responsibilities</h3>\n                                    <ul><li>Provide accurate tender information</li><li>Clearly define tender requirements</li><li>Set realistic submission deadlines</li><li>Upload correct procurement documents</li><li>Define fair evaluation criteria</li><li>Communicate clarifications professionally</li><li>Review bids responsibly</li><li>Make award decisions lawfully and fairly</li><li>Avoid discriminatory, fraudulent, or corrupt practices</li><li>Manage contracts in good faith</li></ul>\n                                </article>\n                                <article>\n                                    <h3>Supplier responsibilities</h3>\n                                    <ul><li>Submit accurate business information</li><li>Read tender requirements carefully</li><li>Submit bids before the deadline</li><li>Provide truthful technical and financial proposals</li><li>Upload valid supporting documents</li><li>Avoid false claims or misleading pricing</li><li>Honour bid validity periods where applicable</li><li>Negotiate honestly</li><li>Perform awarded contracts according to agreed terms</li><li>Avoid bribery, collusion, bid rigging, or unethical conduct</li></ul>\n                                </article>\n                            </div>\n                        </section>\n\n                        <section class=\"terms-section\">\n                            <span class=\"terms-section-label\">Procurement Workflow Terms</span>\n                            <h2>How the Terms Follow the Procurement Journey</h2>\n                            <div class=\"terms-workflow\">\n                                \n                                    <article>\n                                        <span>1</span>\n                                        <strong>Create Tender</strong>\n                                    </article>\n                                \n                                    <article>\n                                        <span>2</span>\n                                        <strong>Publish</strong>\n                                    </article>\n                                \n                                    <article>\n                                        <span>3</span>\n                                        <strong>Submit Bid</strong>\n                                    </article>\n                                \n                                    <article>\n                                        <span>4</span>\n                                        <strong>Evaluate</strong>\n                                    </article>\n                                \n                                    <article>\n                                        <span>5</span>\n                                        <strong>Award</strong>\n                                    </article>\n                                \n                                    <article>\n                                        <span>6</span>\n                                        <strong>Negotiate Contract</strong>\n                                    </article>\n                                \n                                    <article>\n                                        <span>7</span>\n                                        <strong>Accept Contract</strong>\n                                    </article>\n                                \n                                    <article>\n                                        <span>8</span>\n                                        <strong>Manage Post-Award</strong>\n                                    </article>\n                                \n                            </div>\n                        </section>\n\n                        <section id=\"terms-prohibited-cards\" class=\"terms-section terms-warning-section\">\n                            <span class=\"terms-section-label\">Important Rules</span>\n                            <h2>Prohibited Activities</h2>\n                            <div class=\"terms-warning-grid\">\n                                \n                                    <article>\n                                        \n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M12 9v4\"/><path d=\"M12 17h.01\"/><path d=\"M10.3 4.3 2.6 18a2 2 0 0 0 1.7 3h15.4a2 2 0 0 0 1.7-3L13.7 4.3a2 2 0 0 0-3.4 0Z\"/>\n        </svg>\n    \n                                        <h3>Fraud</h3>\n                                        <p>Submitting false information, fake accounts, misleading identity, or false qualifications.</p>\n                                    </article>\n                                \n                                    <article>\n                                        \n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M12 9v4\"/><path d=\"M12 17h.01\"/><path d=\"M10.3 4.3 2.6 18a2 2 0 0 0 1.7 3h15.4a2 2 0 0 0 1.7-3L13.7 4.3a2 2 0 0 0-3.4 0Z\"/>\n        </svg>\n    \n                                        <h3>Bribery</h3>\n                                        <p>Offering, requesting, or accepting improper payments, favours, or benefits.</p>\n                                    </article>\n                                \n                                    <article>\n                                        \n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M12 9v4\"/><path d=\"M12 17h.01\"/><path d=\"M10.3 4.3 2.6 18a2 2 0 0 0 1.7 3h15.4a2 2 0 0 0 1.7-3L13.7 4.3a2 2 0 0 0-3.4 0Z\"/>\n        </svg>\n    \n                                        <h3>Collusion</h3>\n                                        <p>Coordinating bids, sharing confidential evaluation information, or manipulating tender outcomes.</p>\n                                    </article>\n                                \n                                    <article>\n                                        \n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M12 9v4\"/><path d=\"M12 17h.01\"/><path d=\"M10.3 4.3 2.6 18a2 2 0 0 0 1.7 3h15.4a2 2 0 0 0 1.7-3L13.7 4.3a2 2 0 0 0-3.4 0Z\"/>\n        </svg>\n    \n                                        <h3>Fake documents</h3>\n                                        <p>Uploading fake certificates, false licenses, or inaccurate supporting files.</p>\n                                    </article>\n                                \n                                    <article>\n                                        \n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M12 9v4\"/><path d=\"M12 17h.01\"/><path d=\"M10.3 4.3 2.6 18a2 2 0 0 0 1.7 3h15.4a2 2 0 0 0 1.7-3L13.7 4.3a2 2 0 0 0-3.4 0Z\"/>\n        </svg>\n    \n                                        <h3>Unauthorized access</h3>\n                                        <p>Hacking, bypassing controls, reverse engineering, or misusing APIs.</p>\n                                    </article>\n                                \n                                    <article>\n                                        \n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M12 9v4\"/><path d=\"M12 17h.01\"/><path d=\"M10.3 4.3 2.6 18a2 2 0 0 0 1.7 3h15.4a2 2 0 0 0 1.7-3L13.7 4.3a2 2 0 0 0-3.4 0Z\"/>\n        </svg>\n    \n                                        <h3>Harassment</h3>\n                                        <p>Threatening, abusing, spamming, or posting offensive content toward other users.</p>\n                                    </article>\n                                \n                                    <article>\n                                        \n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M12 9v4\"/><path d=\"M12 17h.01\"/><path d=\"M10.3 4.3 2.6 18a2 2 0 0 0 1.7 3h15.4a2 2 0 0 0 1.7-3L13.7 4.3a2 2 0 0 0-3.4 0Z\"/>\n        </svg>\n    \n                                        <h3>Malware</h3>\n                                        <p>Uploading harmful files, malicious links, or content that disrupts platform operations.</p>\n                                    </article>\n                                \n                            </div>\n                        </section>\n\n                        <section class=\"terms-section\">\n                            <span class=\"terms-section-label\">Main Terms Content</span>\n                            <h2>Full Terms and Conditions</h2>\n                            <div class=\"terms-accordion\">\n                                \n                                    <details id=\"terms-introduction\" open>\n                                        <summary>01 Introduction</summary>\n                                        <div>\n        <p>Welcome to ProcureX. These Terms and Conditions govern your access to and use of the ProcureX platform, including the website, web application, mobile-responsive interfaces, procurement tools, tender marketplace, bid submission features, contract management tools, notifications, support services, and any related features provided by ProcureX.</p><p>ProcureX provides a digital environment where buyers and suppliers can participate in procurement activities. The platform is designed to support structured tender creation, supplier participation, bid submission, evaluation, awarding, contract negotiation, and post-award management.</p><p>These Terms apply to all users of ProcureX, including buyers, suppliers, companies, organizations, authorized internal personnel, individual users, invited users, evaluators, and any person who accesses the platform.</p><p>By creating an account, browsing tenders, submitting bids, publishing procurement opportunities, accepting awards, negotiating contracts, or using any ProcureX service, you agree to be bound by these Terms and Conditions.</p>\n        \n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-definitions\" open>\n                                        <summary>02 Definitions</summary>\n                                        <div>\n        \n        \n        \n            <div class=\"terms-clause-group\">\n                <h4>ProcureX</h4>\n                <p>The digital procurement platform, including its website, application, tools, services, systems, and related features.</p>\n                \n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Platform</h4>\n                <p>The ProcureX website, dashboard, tender marketplace, procurement workspace, bid submission system, contract management system, and connected digital services.</p>\n                \n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>User</h4>\n                <p>Any person, company, organization, buyer, supplier, authorized representative, authorized internal user, or visitor who accesses or uses ProcureX.</p>\n                \n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Buyer</h4>\n                <p>A user, company, institution, or organization that creates tenders, publishes procurement opportunities, receives bids, evaluates submissions, awards tenders, and manages contracts.</p>\n                \n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Supplier</h4>\n                <p>A user, company, individual, service provider, contractor, consultant, vendor, or organization that views tenders, submits bids, accepts awards, negotiates contracts, and performs procurement obligations.</p>\n                \n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Tender</h4>\n                <p>A procurement opportunity created by a buyer for goods, works, services, consultancy, or any other procurement category supported by ProcureX.</p>\n                \n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Bid</h4>\n                <p>A supplier response to a tender, including technical proposals, financial proposals, compliance documents, uploaded files, pricing, methodology, and supporting information.</p>\n                \n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Award</h4>\n                <p>A buyer decision to select a supplier for a tender, subject to contract formation, negotiation, acceptance, or other requirements.</p>\n                \n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Contract</h4>\n                <p>The agreement formed between a buyer and a supplier after a tender is awarded and accepted, including negotiated terms, deliverables, milestones, prices, and obligations.</p>\n                \n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Content</h4>\n                <p>Any information, text, documents, files, images, messages, bids, tenders, contracts, data, comments, uploads, or records submitted, created, posted, or stored on ProcureX.</p>\n                \n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Account</h4>\n                <p>The user profile or organization profile created to access ProcureX services.</p>\n                \n            </div>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-acceptance\" >\n                                        <summary>03 Acceptance of These Terms</summary>\n                                        <div>\n        <p>By using ProcureX, you confirm that you have read, understood, and agreed to these Terms and Conditions.</p><p>If you are using ProcureX on behalf of a company, organization, institution, partnership, or other legal entity, you confirm that you have authority to accept these Terms on behalf of that entity.</p><p>If you do not agree to these Terms, you must stop using ProcureX immediately.</p>\n        <ul><li>Create a ProcureX account</li><li>Log into the platform</li><li>Publish a tender</li><li>Submit a bid</li><li>Upload procurement documents</li><li>Participate in contract negotiation</li><li>Accept an award</li><li>Use messaging or clarification tools</li><li>Access tender or supplier information</li><li>Use any feature of the platform</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-eligibility\" >\n                                        <summary>04 Eligibility</summary>\n                                        <div>\n        <p>To use ProcureX, you must be legally capable of creating an account, entering into platform terms, submitting business information, and participating in procurement activities.</p><p>Users must provide accurate information during registration and platform use. ProcureX may require users to verify identity, business information, contact details, licenses, tax details, or other relevant documents before accessing certain features.</p>\n        <ul><li>ProcureX may restrict, suspend, or terminate access if a user provides false or misleading information.</li><li>Uses another person identity without permission.</li><li>Creates an account without authority.</li><li>Violates these Terms.</li><li>Engages in fraud, corruption, collusion, abuse, or unlawful activity.</li><li>Misuses procurement documents or platform features.</li><li>Attempts to bypass platform security controls.</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-accounts\" >\n                                        <summary>05 User Accounts</summary>\n                                        <div>\n        <p>Users may need to create an account to access procurement features on ProcureX.</p><p>ProcureX may support accounts for buyers, suppliers, companies, organizations, individual users, and authorized internal admin users.</p><p>Where a company or organization uses one account, the person managing that account is responsible for ensuring that only authorized representatives use the account. ProcureX is not responsible for losses caused by unauthorized use where the user failed to protect login credentials.</p>\n        <ul><li>Provide accurate and complete information</li><li>Keep account details updated</li><li>Use a secure password</li><li>Keep login credentials confidential</li><li>Notify ProcureX of unauthorized account access</li><li>Accept responsibility for all activities performed under their account</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-roles\" >\n                                        <summary>06 Buyer and Supplier Role Flexibility</summary>\n                                        <div>\n        <p>ProcureX may allow users or organizations to act as both buyers and suppliers depending on their procurement activities.</p><p>Users must ensure they do not misuse this flexibility to create conflicts of interest, manipulate procurement outcomes, submit misleading bids, or gain unfair access to confidential information.</p><p>ProcureX may monitor role-based activity to protect fairness, transparency, and platform integrity.</p>\n        <ul><li>Create tenders as a buyer</li><li>Submit bids as a supplier</li><li>Receive bids from other suppliers</li><li>Participate in other buyers tenders</li><li>Manage awarded contracts from either side</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-buyer-responsibilities\" >\n                                        <summary>07 Buyer Responsibilities</summary>\n                                        <div>\n        <p>Buyers are responsible for the tenders they create and publish on ProcureX.</p><p>Buyers are responsible for ensuring that their tender requirements, evaluation criteria, award decisions, contract terms, and procurement processes comply with applicable laws, internal policies, and organizational rules.</p><p>ProcureX does not guarantee that a buyer tender is legally compliant, commercially reasonable, or suitable for a specific procurement purpose.</p>\n        <ul><li>Provide accurate tender information</li><li>Clearly define tender requirements</li><li>Set realistic submission deadlines</li><li>Upload correct procurement documents</li><li>Define fair evaluation criteria</li><li>Communicate clarifications professionally</li><li>Review bids responsibly</li><li>Make award decisions lawfully and fairly</li><li>Avoid discriminatory, fraudulent, or corrupt practices</li><li>Manage contracts in good faith</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-supplier-responsibilities\" >\n                                        <summary>08 Supplier Responsibilities</summary>\n                                        <div>\n        <p>Suppliers are responsible for the bids, documents, and information they submit through ProcureX.</p><p>Suppliers are responsible for verifying that they meet tender requirements before submitting a bid.</p><p>Submitting a bid does not guarantee that the supplier will be shortlisted, evaluated positively, awarded, contracted, or paid.</p>\n        <ul><li>Submit accurate business information</li><li>Read tender requirements carefully</li><li>Submit bids before the deadline</li><li>Provide truthful technical and financial proposals</li><li>Upload valid supporting documents</li><li>Avoid false claims or misleading pricing</li><li>Honour bid validity periods where applicable</li><li>Negotiate honestly</li><li>Perform awarded contracts according to agreed terms</li><li>Avoid bribery, collusion, bid rigging, or unethical conduct</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-tender-creation\" >\n                                        <summary>09 Tender Creation and Publication</summary>\n                                        <div>\n        <p>ProcureX allows buyers to create and publish tenders for different procurement categories, including goods, works, services, and consultancy.</p><p>Buyers are responsible for reviewing tender details before publication.</p><p>ProcureX does not guarantee that published tenders will receive bids or that submitted bids will meet buyer expectations.</p>\n        \n        \n            <div class=\"terms-clause-group\">\n                <h4>A tender may include</h4>\n                \n                <ul><li>Tender title</li><li>Procurement category</li><li>Scope of work or supply</li><li>Requirements</li><li>Eligibility criteria</li><li>Evaluation criteria</li><li>Submission deadline</li><li>Delivery requirements</li><li>Contract terms</li><li>Payment terms</li><li>Supporting documents</li><li>Clarification instructions</li><li>Bid submission requirements</li></ul>\n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>ProcureX may reject or suspend tenders that</h4>\n                \n                <ul><li>Contain unlawful content</li><li>Promote prohibited goods or services</li><li>Include misleading information</li><li>Violate platform rules</li><li>Contain abusive, discriminatory, or harmful language</li><li>Appear fraudulent or suspicious</li><li>Create security, legal, or reputational risk</li></ul>\n            </div>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-marketplace\" >\n                                        <summary>10 Tender Marketplace</summary>\n                                        <div>\n        <p>The ProcureX tender marketplace allows suppliers to view procurement opportunities published by buyers.</p><p>Tender visibility may depend on tender status, buyer settings, supplier eligibility, procurement category, access restrictions, subscription or platform plan, geographic filters, or business category filters.</p><p>ProcureX may organize, display, recommend, or rank tenders based on platform logic, user preferences, categories, relevance, or other factors.</p><p>Users must not scrape, copy, misuse, resell, or redistribute tender marketplace data without permission.</p>\n        \n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-bid-submission\" >\n                                        <summary>11 Bid Submission</summary>\n                                        <div>\n        <p>Suppliers may submit bids in response to tenders through ProcureX.</p><p>Suppliers are responsible for ensuring that their bids are complete, accurate, and submitted before the deadline. ProcureX may not allow changes after submission or after the deadline unless the platform, buyer, or applicable rules permit it.</p><p>ProcureX is not responsible for missed deadlines caused by internet failure, device issues, user mistakes, incomplete uploads, late submission, wrong file format, incorrect information, or failure to review submission before sending. Suppliers should submit bids early enough to avoid technical or timing problems.</p>\n        <ul><li>Technical proposal</li><li>Financial proposal</li><li>Pricing schedule</li><li>Delivery plan</li><li>Methodology</li><li>Work program</li><li>Team details</li><li>Experience and qualifications</li><li>Compliance documents</li><li>Licenses and certificates</li><li>Uploaded supporting files</li><li>Clarification responses</li><li>Contract acceptance notes</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-bid-validity\" >\n                                        <summary>12 Bid Validity</summary>\n                                        <div>\n        <p>A supplier bid may remain valid for the period stated in the tender.</p><p>If a supplier needs to withdraw or correct a bid, the supplier must follow the process allowed by the buyer, tender rules, and platform settings.</p><p>ProcureX is not responsible for losses arising from a supplier submitting incorrect pricing, wrong documents, or unrealistic commitments.</p>\n        <ul><li>Quoted prices</li><li>Delivery timelines</li><li>Proposed methodology</li><li>Technical commitments</li><li>Warranty terms</li><li>Staffing commitments</li><li>Service levels</li><li>Contract assumptions</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-clarifications\" >\n                                        <summary>13 Clarifications and Communication</summary>\n                                        <div>\n        <p>ProcureX may allow suppliers to ask clarification questions and buyers to respond through the platform.</p><p>Users agree to communicate professionally and respectfully. ProcureX may monitor, restrict, or remove communications that violate these Terms or platform rules.</p>\n        <ul><li>Do not harass other users</li><li>Do not share offensive content</li><li>Do not request bribes or favours</li><li>Do not exchange prohibited information</li><li>Do not manipulate tender outcomes</li><li>Do not bypass platform procedures</li><li>Do not share malware, spam, or harmful links</li><li>Do not conduct unrelated business outside the tender process</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-evaluation\" >\n                                        <summary>14 Evaluation of Bids</summary>\n                                        <div>\n        <p>ProcureX may provide tools to help buyers evaluate submitted bids. Buyers may define their own evaluation criteria during tender creation.</p><p>Buyers are responsible for applying evaluation criteria fairly and consistently.</p><p>ProcureX may provide structure, scoring fields, comparison tools, status tracking, and document access, but ProcureX does not make procurement decisions on behalf of buyers unless explicitly stated.</p><p>ProcureX is not responsible for buyer evaluation decisions, scoring outcomes, award choices, or rejection of bids.</p>\n        <ul><li>Technical compliance</li><li>Financial proposal</li><li>Supplier experience</li><li>Delivery schedule</li><li>Methodology</li><li>Quality assurance</li><li>Risk management</li><li>Legal compliance</li><li>Required documents</li><li>Past performance</li><li>Price competitiveness</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-awarding\" >\n                                        <summary>15 Awarding</summary>\n                                        <div>\n        <p>After evaluation, a buyer may decide to award a tender to one or more suppliers, depending on the tender structure.</p><p>An award does not always mean that a final contract is already formed. A final contract may depend on supplier acceptance, negotiation, document completion, approvals, due diligence, legal review, payment terms agreement, signature, or final confirmation.</p><p>ProcureX is not responsible if a buyer cancels, withdraws, delays, or changes an award where allowed by applicable rules or tender conditions.</p>\n        <ul><li>Tender reference</li><li>Awarded supplier</li><li>Award status</li><li>Award date</li><li>Award amount</li><li>Next steps</li><li>Contract preparation instructions</li><li>Acceptance deadline</li><li>Buyer comments</li><li>Conditions of award</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-contracting\" >\n                                        <summary>16 Contracting</summary>\n                                        <div>\n        <p>After a tender is awarded, ProcureX may support contract preparation and management between the buyer and awarded supplier.</p><p>The buyer and supplier are responsible for reviewing, understanding, and accepting contract terms.</p><p>ProcureX may provide templates, clause libraries, workflow tools, negotiation records, and digital acceptance features, but ProcureX is not a party to the contract between buyer and supplier unless expressly stated.</p>\n        <ul><li>Scope of supply or services</li><li>Contract value</li><li>Payment terms</li><li>Delivery timelines</li><li>Milestones</li><li>Service levels</li><li>Quality standards</li><li>Penalties</li><li>Warranties</li><li>Termination clauses</li><li>Confidentiality obligations</li><li>Dispute resolution provisions</li><li>Applicable law</li><li>Signatures or approvals</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-negotiation\" >\n                                        <summary>17 Contract Negotiation</summary>\n                                        <div>\n        <p>ProcureX may allow buyers and awarded suppliers to negotiate contract terms before final acceptance.</p><p>Users agree to negotiate in good faith and avoid misleading statements or unfair pressure.</p><p>ProcureX may store negotiation history, revised clauses, comments, timestamps, and acceptance records for accountability.</p><p>A contract should only be accepted when both parties are satisfied with the final terms.</p>\n        <ul><li>Scope adjustments</li><li>Delivery timelines</li><li>Payment terms</li><li>Contract clauses</li><li>Milestones</li><li>Performance obligations</li><li>Warranty terms</li><li>Risk allocation</li><li>Termination conditions</li><li>Reporting requirements</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-post-award\" >\n                                        <summary>18 Post-Award Management</summary>\n                                        <div>\n        <p>ProcureX may support post-award procurement activities after contract acceptance.</p><p>Buyers and suppliers are responsible for performing their obligations under the contract.</p><p>ProcureX does not guarantee supplier performance, buyer payment, project completion, product quality, service quality, or contract success.</p>\n        <ul><li>Milestone tracking</li><li>Delivery confirmation</li><li>Service reporting</li><li>Work progress updates</li><li>Uploading completion evidence</li><li>Performance monitoring</li><li>Issue reporting</li><li>Payment milestone tracking</li><li>Contract amendments</li><li>Contract closure</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-payments\" >\n                                        <summary>19 Platform Fees and Payments</summary>\n                                        <div>\n        <p>ProcureX may charge fees for certain services, subscriptions, premium features, transaction support, tender publishing, supplier access, contract tools, or other platform services.</p><p>ProcureX will display applicable fees before charging users where required. Users are responsible for paying all applicable fees, taxes, charges, and payment processing costs associated with paid services.</p><p>ProcureX may suspend or restrict paid features if payment fails, is reversed, is disputed, or remains unpaid. Unless stated otherwise, platform fees are non-refundable once services have been provided.</p>\n        <ul><li>User type</li><li>Account plan</li><li>Tender volume</li><li>Marketplace access</li><li>Subscription level</li><li>Contract management features</li><li>Premium visibility</li><li>Verification services</li><li>Platform support services</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-transactions\" >\n                                        <summary>20 Transactions Between Buyers and Suppliers</summary>\n                                        <div>\n        <p>ProcureX provides technology tools to support procurement interactions, but the actual commercial relationship is between the buyer and supplier.</p><p>Unless expressly stated, ProcureX is not the buyer, supplier, contractor, consultant, employer, agent of either party, guarantor of performance, guarantor of payment, or legal representative of either party.</p><p>Buyers and suppliers are responsible for reviewing each other information, conducting due diligence, negotiating contract terms, confirming pricing, managing performance, handling payments, resolving disputes, and complying with applicable laws.</p><p>ProcureX is not liable for losses arising from a buyer or supplier failure to perform contractual obligations.</p>\n        \n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-prohibited\" >\n                                        <summary>21 Prohibited Activities</summary>\n                                        <div>\n        <p>Users must not misuse ProcureX. ProcureX may suspend, restrict, investigate, or terminate accounts involved in prohibited activities.</p>\n        \n        \n            <div class=\"terms-clause-group\">\n                <h4>Fraud and Misrepresentation</h4>\n                \n                <ul><li>Submitting false information</li><li>Uploading fake documents</li><li>Misrepresenting business identity</li><li>Creating fake accounts</li><li>Pretending to represent another organization</li><li>Providing false qualifications or certificates</li></ul>\n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Corruption and Unethical Conduct</h4>\n                \n                <ul><li>Offering bribes</li><li>Requesting bribes</li><li>Colluding with other bidders</li><li>Manipulating tender outcomes</li><li>Engaging in bid rigging</li><li>Sharing confidential evaluation information</li><li>Using insider information unfairly</li></ul>\n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Platform Abuse</h4>\n                \n                <ul><li>Hacking or attempting unauthorized access</li><li>Uploading malware</li><li>Scraping platform data</li><li>Disrupting platform operations</li><li>Bypassing security controls</li><li>Reverse engineering platform systems</li><li>Creating automated fake activity</li><li>Misusing APIs or integrations</li></ul>\n            </div>\n        \n            <div class=\"terms-clause-group\">\n                <h4>Harmful Conduct</h4>\n                \n                <ul><li>Harassing users</li><li>Sending spam</li><li>Posting offensive content</li><li>Sharing illegal material</li><li>Violating intellectual property rights</li><li>Using the platform for unlawful transactions</li></ul>\n            </div>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-content\" >\n                                        <summary>22 User Content</summary>\n                                        <div>\n        <p>Users may upload, submit, create, or share content through ProcureX, including tenders, bids, contracts, documents, messages, images, certificates, drawings, and other files.</p><p>Users remain responsible for their content. ProcureX may remove or restrict content that violates these Terms, platform policies, or applicable law.</p><p>Users grant ProcureX permission to store, process, display, transmit, and use uploaded content as necessary to operate the platform and provide procurement services.</p>\n        <ul><li>Users confirm they have the right to upload the content</li><li>The content is accurate to the best of their knowledge</li><li>The content does not violate any law</li><li>The content does not infringe another party rights</li><li>The content does not contain harmful software</li><li>The content is relevant to the procurement activity</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-confidentiality\" >\n                                        <summary>23 Confidentiality</summary>\n                                        <div>\n        <p>Procurement activities may involve confidential business, technical, financial, legal, and commercial information. Users agree to handle confidential information responsibly.</p><p>Users must not disclose confidential information obtained through ProcureX unless authorized, required for the procurement process, required by law, already publicly available, or permitted by the relevant party.</p><p>ProcureX may use access controls to restrict confidential information to authorized users.</p>\n        <ul><li>Tender documents</li><li>Bid submissions</li><li>Financial proposals</li><li>Technical proposals</li><li>Evaluation records</li><li>Contract terms</li><li>Pricing schedules</li><li>Negotiation comments</li><li>Drawings and specifications</li><li>Supplier documents</li><li>Buyer internal information</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-ip\" >\n                                        <summary>24 Intellectual Property Rights</summary>\n                                        <div>\n        <p>ProcureX owns or licenses all rights in the platform, including software, interface design, logos, branding, workflows, features, databases, system architecture, platform content created by ProcureX, documentation, and design components.</p><p>Users must not copy, modify, sell, distribute, reverse engineer, or exploit ProcureX intellectual property without permission.</p><p>Users retain ownership of their own uploaded content, such as business documents, tender documents, bid files, and contract attachments, subject to the rights granted to ProcureX for platform operation.</p>\n        \n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-privacy\" >\n                                        <summary>25 Privacy and Data Protection</summary>\n                                        <div>\n        <p>ProcureX collects and processes user information according to its Privacy Policy. By using ProcureX, users agree that ProcureX may collect, process, store, and use information as described in the Privacy Policy.</p><p>This may include account information, business information, tender information, bid information, contract information, communication records, platform activity logs, and technical information.</p><p>Users must also respect the privacy and data protection rights of other users. Users must not collect, misuse, publish, sell, or disclose personal data obtained through ProcureX unless permitted by law and platform rules.</p>\n        \n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-availability\" >\n                                        <summary>26 Platform Availability</summary>\n                                        <div>\n        <p>ProcureX aims to provide a reliable digital procurement platform. However, we do not guarantee that the platform will always be available, uninterrupted, error-free, or free from technical issues.</p><p>Platform access may be affected by maintenance, updates, internet issues, hosting problems, cybersecurity incidents, third-party service failures, device or browser problems, force majeure events, or system overload.</p><p>ProcureX may suspend or limit access temporarily to maintain, improve, protect, or update the platform. Users are responsible for submitting tenders, bids, documents, and responses early enough to avoid deadline risks caused by technical issues.</p>\n        \n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-security\" >\n                                        <summary>27 Security</summary>\n                                        <div>\n        <p>ProcureX may use security measures to protect the platform and user information. ProcureX may investigate suspicious activity and take action to protect the platform.</p><p>Users are responsible for keeping passwords confidential, using secure devices, logging out after use, reporting suspicious activity, avoiding shared or public devices for sensitive actions, and not uploading malware or harmful files.</p>\n        <ul><li>Password protection</li><li>Authentication controls</li><li>Role-based permissions</li><li>Secure document storage</li><li>Activity logs</li><li>System monitoring</li><li>Encryption where appropriate</li><li>Backup procedures</li><li>Authorized internal access controls</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-termination\" >\n                                        <summary>28 Suspension and Termination of Accounts</summary>\n                                        <div>\n        <p>ProcureX may suspend, restrict, or terminate a user account if the user violates these Terms, provides false information, misuses the platform, engages in fraud or corruption, uploads harmful content, fails to pay applicable fees, creates legal or security risk, harasses or harms other users, violates procurement rules, attempts unauthorized access, or causes reputational harm to ProcureX.</p><p>Users may also request account deactivation or deletion, subject to legal, contractual, procurement, audit, and record-keeping requirements.</p><p>Termination of an account does not automatically delete procurement records that must be retained for legal, contractual, dispute, or operational purposes.</p>\n        \n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-disclaimers\" >\n                                        <summary>29 Disclaimers</summary>\n                                        <div>\n        <p>ProcureX provides a digital platform for procurement management. The platform is provided on an as is and as available basis.</p><p>Users should conduct their own due diligence before entering into procurement transactions, awarding tenders, accepting contracts, or making payments.</p>\n        <ul><li>ProcureX does not guarantee that every tender will receive bids</li><li>Every supplier is qualified</li><li>Every buyer is reliable</li><li>Bids will be accurate</li><li>Contracts will be performed successfully</li><li>Payments will be made on time</li><li>Users will comply with laws</li><li>Procurement decisions will be correct</li><li>Documents uploaded by users are genuine</li><li>The platform will be uninterrupted or error-free</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-liability\" >\n                                        <summary>30 Limitation of Liability</summary>\n                                        <div>\n        <p>To the maximum extent permitted by law, ProcureX is not liable for indirect, incidental, special, consequential, punitive, or economic losses arising from use of the platform.</p><p>ProcureX total liability, where liability cannot be excluded, may be limited to the amount paid by the user to ProcureX for the relevant service during a defined period, unless applicable law requires otherwise.</p>\n        <ul><li>Lost profits</li><li>Lost business opportunities</li><li>Failed tenders</li><li>Rejected bids</li><li>Contract disputes</li><li>Payment disputes</li><li>Supplier non-performance</li><li>Buyer non-payment</li><li>Data loss</li><li>Technical failure</li><li>Account misuse</li><li>Unauthorized access</li><li>User misconduct</li><li>Incorrect information submitted by users</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-indemnity\" >\n                                        <summary>31 Indemnity</summary>\n                                        <div>\n        <p>Users agree to protect and hold ProcureX harmless from claims, losses, damages, liabilities, costs, and expenses arising from user actions or failures.</p>\n        <ul><li>User violation of these Terms</li><li>False or misleading information</li><li>Uploaded content</li><li>Procurement disputes</li><li>Contract disputes</li><li>Breach of confidentiality</li><li>Violation of law</li><li>Infringement of third-party rights</li><li>Fraud, corruption, or misconduct</li><li>Unauthorized use of an account</li><li>Misuse of platform features</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-disputes\" >\n                                        <summary>32 Disputes Between Buyers and Suppliers</summary>\n                                        <div>\n        <p>ProcureX may provide tools to support communication, issue tracking, negotiation, document history, and dispute records. However, disputes between buyers and suppliers are primarily the responsibility of the parties involved.</p><p>Users should first attempt to resolve disputes through professional communication and contract terms.</p><p>ProcureX may assist by providing platform records, where appropriate and permitted, but ProcureX is not required to act as a court, arbitrator, mediator, or legal representative unless expressly agreed.</p>\n        <ul><li>Bid rejection disputes</li><li>Award disputes</li><li>Contract interpretation disputes</li><li>Delivery disputes</li><li>Payment disputes</li><li>Quality disputes</li><li>Delay claims</li><li>Termination disputes</li><li>Confidentiality disputes</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-law\" >\n                                        <summary>33 Governing Law</summary>\n                                        <div>\n        <p>These Terms and Conditions should be governed by the laws of the jurisdiction where ProcureX is legally registered or operates.</p><p>For a Tanzania-based ProcureX platform, the governing law may be the laws of the United Republic of Tanzania, unless otherwise stated in a specific agreement.</p><p>Any disputes involving ProcureX may be handled by the courts or dispute resolution bodies specified in these Terms, the user agreement, or applicable law. This section should be reviewed by a lawyer before publication to ensure the correct jurisdiction, court, arbitration, or mediation process is selected.</p>\n        \n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-changes\" >\n                                        <summary>34 Changes to Terms and Conditions</summary>\n                                        <div>\n        <p>ProcureX may update these Terms and Conditions from time to time to reflect new platform features, legal or regulatory updates, security improvements, business model changes, payment changes, procurement process updates, user feedback, or operational requirements.</p><p>When Terms are updated, ProcureX may notify users through platform notification, email, login notice, updated effective date, or public announcement on the website.</p><p>Continued use of ProcureX after changes become effective means the user accepts the updated Terms.</p>\n        \n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-contact\" >\n                                        <summary>35 Contact Us</summary>\n                                        <div>\n        <p>If you have questions about these Terms and Conditions, you may contact ProcureX.</p><p>Platform: ProcureX. Email: support@procurex.com. Legal Contact: legal@procurex.com. Location: Tanzania.</p>\n        \n        \n    </div>\n                                    </details>\n                                \n                                    <details id=\"terms-acknowledgement\" >\n                                        <summary>36 User Acknowledgement</summary>\n                                        <div>\n        <p>By using ProcureX, you confirm the following. If you do not agree with these Terms, you should not use ProcureX.</p>\n        <ul><li>You have read these Terms and Conditions</li><li>You understand your responsibilities</li><li>You agree to use the platform lawfully</li><li>You will provide accurate information</li><li>You will respect other users</li><li>You will protect confidential information</li><li>You will comply with applicable procurement rules</li><li>You accept that ProcureX is a platform provider and not automatically a party to buyer-supplier contracts</li></ul>\n        \n    </div>\n                                    </details>\n                                \n                            </div>\n                        </section>\n\n                        <section id=\"terms-contact-form\" class=\"terms-section terms-contact-section\">\n                            <div>\n                                <span class=\"terms-section-label\">Contact Us</span>\n                                <h2>Contact ProcureX About These Terms</h2>\n                                <p>If you have questions about these Terms and Conditions, you may contact ProcureX.</p>\n                                <div class=\"terms-contact-details\">\n                                    <span><strong>Platform</strong> ProcureX</span>\n                                    <span><strong>Email</strong> <a href=\"mailto:support@procurex.com\">support@procurex.com</a></span>\n                                    <span><strong>Legal Contact</strong> <a href=\"mailto:legal@procurex.com\">legal@procurex.com</a></span>\n                                    <span><strong>Location</strong> Tanzania</span>\n                                </div>\n                            </div>\n\n                            <article class=\"terms-contact-panel\">\n                                \n        <svg class=\"terms-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.1\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\">\n            <path d=\"M21 15a4 4 0 0 1-4 4H8l-5 3V7a4 4 0 0 1 4-4h10a4 4 0 0 1 4 4z\"/><path d=\"M8 9h8\"/><path d=\"M8 13h5\"/>\n        </svg>\n    \n                                <h3>Use the dedicated contact page</h3>\n                                <p>Terms questions and support messages are now handled through one separate ProcureX contact form.</p>\n                                <button class=\"btn btn-primary\" type=\"button\" data-navigate=\"contact\">Open Contact Page</button>\n                            </article>\n                        </section>\n                    </div>\n                </div>\n\n                <section class=\"terms-final-cta\">\n                    <div class=\"terms-container terms-final-panel\">\n                        <div>\n                            <span class=\"terms-section-label\">Ready to Use ProcureX Responsibly?</span>\n                            <h2>Continue with a clear understanding of your responsibilities.</h2>\n                            <p>By continuing to use ProcureX, you agree to follow these Terms and Conditions and use the platform in a lawful, fair, and professional manner.</p>\n                            <label class=\"terms-final-check\">\n                                <input type=\"checkbox\">\n                                <span>I have read and agree to the ProcureX Terms and Conditions.</span>\n                            </label>\n                        </div>\n                        <div class=\"terms-actions\">\n                            <button class=\"btn btn-primary\" type=\"button\" data-navigate=\"register\">Accept and Continue</button>\n                            <button class=\"btn btn-secondary\" type=\"button\" data-navigate=\"contact\">Contact Support</button>\n                        </div>\n                    </div>\n                </section>\n            </main>\n\n            <footer class=\"terms-footer\">\n                <div class=\"terms-container\">\n                    <strong>ProcureX</strong>\n                    <p>Use ProcureX lawfully, fairly, and professionally across every tender, bid, contract, and procurement record.</p>\n                </div>\n            </footer>\n        </div>\n    ";

export function TermsAndConditionsProcurexPage() {
  return <PublicContentProcurexPage pageKey="terms-and-conditions" fallbackHtml={html} />;
}
